#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>

char *gen_token() {
    static char token[33];
    int fd = open("/dev/urandom", O_RDONLY);
    if (fd < 0) return NULL;
    unsigned char buf[16];
    if (read(fd, buf, sizeof(buf)) != sizeof(buf)) {
        close(fd);
        return NULL;
    }
    close(fd);
    for (int i = 0; i < 16; i++) {
        sprintf(token + i * 2, "%02x", buf[i]);
    }
    token[32] = '\0';
    return token;
}

